// // This module calculates the sum of two inputs if the first is less than the second, otherwise it calculates the difference.
module compare (
    input [7:0] a,
    input [7:0] b,
    output reg [7:0] out
);

always @(a, b) begin
    if(a >= b) begin
        out = a - b;
    end else begin
        out = a + b;
    end
end

endmodule
